import java.util.Scanner;

public class SecureBufferImplementation {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Define a maximum buffer size to prevent buffer overflow
        int maxLength = 10;

        // Check if the input exceeds the maximum allowed length
        if (name.length() > maxLength) {
            System.out.println("Input exceeds maximum allowed length.");
            return;
        }

        // Copy user input 'name' into a correctly sized buffer
        char[] buffer = new char[name.length()];
        name.getChars(0, name.length(), buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

